```python
def flatten_dict(d: dict, parent_key: str = "", sep: str = ".") -> dict:
    """
    Flatten a nested dictionary into a single-level dictionary.

    Args:
        d:          The dictionary to flatten.
        parent_key: Prefix for the current level's keys (used in recursion).
        sep:        Separator between key levels. Defaults to ".".

    Returns:
        A flat dictionary with compound keys joined by `sep`.

    Example:
        >>> flatten_dict({"a": {"b": {"c": 1}}, "d": 2})
        {'a.b.c': 1, 'd': 2}
    """
    items = {}
    for key, value in d.items():
        new_key = f"{parent_key}{sep}{key}" if parent_key else str(key)
        if isinstance(value, dict):
            items.update(flatten_dict(value, new_key, sep=sep))
        else:
            items[new_key] = value
    return items
```

---

### Usage Examples

```python
# Basic nested dict
data = {
    "user": {
        "name": "Alice",
        "address": {
            "city": "Vienna",
            "zip": "1010"
        }
    },
    "active": True
}

flatten_dict(data)
# {
#   'user.name': 'Alice',
#   'user.address.city': 'Vienna',
#   'user.address.zip': '1010',
#   'active': True
# }

# Custom separator
flatten_dict(data, sep="__")
# {
#   'user__name': 'Alice',
#   'user__address__city': 'Vienna',
#   'user__address__zip': '1010',
#   'active': True
# }

# Already-flat dict (no-op)
flatten_dict({"a": 1, "b": 2})
# {'a': 1, 'b': 2}
```

---

### How It Works

| Step | What happens |
|------|-------------|
| Iterate | Walk every `key: value` pair at the current level |
| Build key | Prepend `parent_key + sep` if we're in a nested call |
| Recurse | If `value` is a `dict`, dive deeper, carrying the compound key as the new prefix |
| Collect | Otherwise store the final `key: value` in the result |

---

### Variants Worth Knowing

**Handle lists too** (flatten list values by index):
```python
def flatten_dict_with_lists(d, parent_key="", sep="."):
    items = {}
    for key, value in d.items():
        new_key = f"{parent_key}{sep}{key}" if parent_key else str(key)
        if isinstance(value, dict):
            items.update(flatten_dict_with_lists(value, new_key, sep))
        elif isinstance(value, list):
            for i, item in enumerate(value):
                list_key = f"{new_key}{sep}{i}"
                if isinstance(item, dict):
                    items.update(flatten_dict_with_lists(item, list_key, sep))
                else:
                    items[list_key] = item
        else:
            items[new_key] = value
    return items
```

**Unflatten** (reverse operation):
```python
def unflatten_dict(d: dict, sep: str = ".") -> dict:
    result = {}
    for compound_key, value in d.items():
        keys = compound_key.split(sep)
        node = result
        for k in keys[:-1]:
            node = node.setdefault(k, {})
        node[keys[-1]] = value
    return result
```

